+import { $internal } from '../common';
+import type { Schema } from '../storage';
+import type { Trait, TraitRecord, TraitValue } from './types';
+
+let aspectId = 1_000_000_000;
+
+export type Aspect<T extends readonly Trait[] = readonly Trait[]> = {
+    readonly id: number;
+    readonly traits: T;
+    readonly schema: Schema;
+} & ((params?: AspectValue<T>) => [Aspect<T>, AspectValue<T>]);
+
+export type AspectValue<T extends readonly Trait[]> = Partial<
+    UnionToIntersection<T[number] extends Trait ? TraitRecord<T[number]> : never>
+>;
+
+type UnionToIntersection<U> = (U extends any ? (value: U) => void : never) extends (
+    value: infer I
+) => void
+    ? I
+    : never;
+
+export function isAspect(value: unknown): value is Aspect {
+    return typeof value === 'function' && Array.isArray((value as Aspect).traits);
+}
+
+/** Creates a composite trait view over two or more non-relation traits. */
+export function createAspect<const T extends readonly (Trait | Aspect)[]>(...inputs: T): Aspect {
+    if (inputs.length < 2) throw new Error('createAspect requires at least two traits');
+
+    const traits: Trait[] = [];
+    const fields = new Set<string>();
+    const schema: Record<string, any> = {};
+
+    for (const input of inputs) {
+        const constituents = isAspect(input) ? input.traits : [input];
+        for (const trait of constituents) {
+            if (trait[$internal].relation) {
+                throw new Error('Relations cannot be constituents of an aspect');
+            }
+            for (const field of Object.keys(trait.schema)) {
+                if (fields.has(field)) {
+                    throw new Error(`Aspect constituents cannot share the field "${field}"`);
+                }
+                fields.add(field);
+                schema[field] = (trait.schema as Record<string, any>)[field];
+            }
+            traits.push(trait);
+        }
+    }
+
+    const id = aspectId++;
+    const Aspect = Object.assign((params: any = {}) => [Aspect, params], { traits }) as Aspect;
+    Object.defineProperties(Aspect, {
+        id: { value: id, enumerable: true },
+        traits: { value: Object.freeze(traits), enumerable: true },
+        schema: { value: Object.freeze(schema), enumerable: true },
+    });
+    return Aspect;
+}
+
+export function splitAspectValue(aspect: Aspect, value: Record<string, any> = {}) {
+    return aspect.traits.map((trait) => {
+        const partial: Record<string, any> = {};
+        for (const key of Object.keys(trait.schema)) {
+            if (key in value) partial[key] = value[key];
+        }
+        return partial;
+    });
+}
