+describe('aspects', () => {
+    const Position = trait({ x: 0, y: 0 });
+    const Velocity = trait({ dx: 0, dy: 0 });
+    const Name = trait({ name: '' });
+    const Marker = trait();
+    const Motion = createAspect(Position, Velocity, Marker);
+
+    it('flattens nested aspects and rejects invalid constituents', () => {
+        const NamedMotion = createAspect(Motion, Name);
+        expect(NamedMotion.traits).toEqual([Position, Velocity, Marker, Name]);
+        expect(() => createAspect(Position, trait({ x: 1 }))).toThrow('share the field');
+        expect(Motion).not.toBe(createAspect(Position, Velocity));
+    });
+
+    it('merges entity operations and distributes fields', () => {
+        const world = createWorld();
+        const entity = world.spawn(Motion({ x: 2, dy: 3 }));
+        expect(entity.has(Motion)).toBe(true);
+        expect(entity.get(Motion)).toEqual({ x: 2, y: 0, dx: 0, dy: 3 });
+        entity.set(Motion, { y: 4, dx: 5 });
+        expect(entity.get(Position)).toEqual({ x: 2, y: 4 });
+        expect(entity.get(Velocity)).toEqual({ dx: 5, dy: 3 });
+        entity.remove(Motion);
+        expect(entity.has(Motion)).toBe(false);
+    });
